def is_valid_url(url):
    # Implement your URL validation logic here, e.g., checking hostnames, paths, etc.
    import re
    # A simple regex for demonstration purposes
    regex = re.compile(
        r'^(http|https)://'  # http:// or https://
        r'(([a-zA-Z0-9\-_]+\.)+[a-zA-Z]{2,}))'  # domain...
        r'(\/.*)?$'  # ...and optional path
    )
    return re.match(regex, url) is not None